// ─── Watchout Timeline Discovery ───────────────────────────────────
// Fetch timelines from Watchout, compare to stored mapping,
// store pending diff in flow context, output diff for UI display.

'use strict';

const http = require('http');

const cfg  = flow.get('watchout_config') || {};
const host = cfg.host || 'localhost';
const port = cfg.port || 3019;
const REQUEST_TIMEOUT_MS = 10000;

// ── Helpers ─────────────────────────────────────────────────────────

function httpGet(path) {
    return new Promise((resolve, reject) => {
        const req = http.request(
            { hostname: host, port, path, method: 'GET',
              headers: { 'Content-Type': 'application/json' } },
            (res) => {
                let data = '';
                res.on('data', c => { data += c; });
                res.on('end', () => {
                    try { resolve({ statusCode: res.statusCode, body: JSON.parse(data) }); }
                    catch(e) { resolve({ statusCode: res.statusCode, body: data }); }
                });
                res.on('error', reject);
            }
        );
        req.on('error', reject);
        req.setTimeout(REQUEST_TIMEOUT_MS, () => req.destroy(new Error('Request timed out')));
        req.end();
    });
}

function parseTimelineName(name) {
    if (!name || name.startsWith('_')) return null;
    return name.trim().toLowerCase().replace(/\s+/g, '_').replace(/[^a-z0-9_]/g, '');
}

function compareMapping(oldMap, newMap) {
    const oldKeys = Object.keys(oldMap);
    const newKeys = Object.keys(newMap);
    return {
        removed:   oldKeys.filter(k => !(k in newMap)),
        added:     newKeys.filter(k => !(k in oldMap)),
        unchanged: oldKeys.filter(k => (k in newMap) && oldMap[k] === newMap[k]),
        changed:   oldKeys.filter(k => (k in newMap) && oldMap[k] !== newMap[k]),
    };
}

function formatDiff(diff) {
    const lines = [];
    diff.removed.forEach(n   => lines.push('REMOVED  : Timeline \'' + n + '\' no longer exists'));
    diff.added.forEach(n     => lines.push('ADDED    : New timeline \'' + n + '\' discovered'));
    diff.changed.forEach(n   => lines.push('CHANGED  : Timeline \'' + n + '\' ID has changed'));
    diff.unchanged.forEach(n => lines.push('OK       : \'' + n + '\''));
    return lines;
}

// ── Main ─────────────────────────────────────────────────────────────

async function discover() {
    let result;
    try {
        result = await httpGet('/v0/timelines');
    } catch(err) {
        return { status: 'error', error: 'Connection failed: ' + err.message };
    }

    if (result.statusCode !== 200) {
        return { status: 'error', error: 'Watchout returned HTTP ' + result.statusCode };
    }

    const timelines = Array.isArray(result.body) ? result.body : [];

    const newMapping = {};
    timelines.forEach(tl => {
        const contentId = parseTimelineName(tl.name);
        if (contentId) newMapping[contentId] = String(tl.id);
    });

    const storedMapping = flow.get('watchout_mapping') || {};
    const diff     = compareMapping(storedMapping, newMapping);
    const hasChanges = diff.added.length > 0 || diff.removed.length > 0 || diff.changed.length > 0;

    flow.set('watchout_pending', newMapping);

    return {
        status:     hasChanges ? 'diff_ready' : 'no_changes',
        hasChanges,
        diff,
        newMapping,
        diffLines:  formatDiff(diff),
    };
}

discover().then(payload => {
    node.send({ payload, topic: 'watchout/discovery' });
}).catch(err => {
    node.send({ payload: { status: 'error', error: err.message }, topic: 'watchout/discovery' });
});

return null;

// Prepare mapping JSON for file write
const pending = flow.get('watchout_pending');
if (!pending) {
    node.send({ payload: { status: 'nothing_pending' }, topic: 'watchout/confirm' });
    return null;
}

// Update flow context immediately
flow.set('watchout_mapping', pending);
flow.set('watchout_pending', null);

// Prepare file write
const cfg = flow.get('watchout_config') || {};
msg.filename = cfg.mappingFile || '/data/watchout/timeline-mapping.json';
msg.payload  = JSON.stringify({ mapping: pending, lastSaved: new Date().toISOString() }, null, 2);
msg._pendingMapping = pending;
msg._savedAt = new Date().toISOString();
return msg;

// Confirm & Save completed
const mapping = msg._pendingMapping || flow.get('watchout_mapping') || {};
node.status({ fill: 'green', shape: 'dot', text: 'Saved: ' + Object.keys(mapping).length + ' timelines' });
node.send({
    payload: {
        status:  'saved',
        mapping: mapping,
        savedAt: msg._savedAt || new Date().toISOString()
    },
    topic: 'watchout/confirm'
});
return null;

// Cancel pending discovery
flow.set('watchout_pending', null);
node.send({ payload: { status: 'cancelled' }, topic: 'watchout/cancel' });
return null;

// ─── Watchout Timeline Control ─────────────────────────────────────
// Input msg.payload: { command, contentId, varName, varValue }

'use strict';

const http = require('http');

const cfg  = flow.get('watchout_config') || {};
const host = cfg.host || 'localhost';
const port = cfg.port || 3019;
const REQUEST_TIMEOUT_MS = 10000;

function httpRequest(method, urlPath, body) {
    return new Promise((resolve, reject) => {
        const opts = { hostname: host, port, path: urlPath, method,
                       headers: { 'Content-Type': 'application/json' } };
        const req = http.request(opts, (res) => {
            let data = '';
            res.on('data', c => { data += c; });
            res.on('end', () => {
                try { resolve({ statusCode: res.statusCode, body: JSON.parse(data) }); }
                catch(e) { resolve({ statusCode: res.statusCode, body: data }); }
            });
            res.on('error', reject);
        });
        req.on('error', reject);
        req.setTimeout(REQUEST_TIMEOUT_MS, () => req.destroy(new Error('Request timed out')));
        if (body !== undefined) req.write(JSON.stringify(body));
        req.end();
    });
}

function resolveTimelineId(contentId) {
    const mapping = flow.get('watchout_mapping') || {};
    const entry = mapping[contentId];
    if (entry === undefined || entry === null) return String(contentId);
    return String(entry);
}

const input   = msg.payload || {};
const command = input.command;

async function execute() {
    let timelineId;
    switch (command) {
        case 'start': {
            timelineId = resolveTimelineId(input.contentId);
            const r = await httpRequest('POST', '/v0/timelines/' + timelineId + '/play');
            return { success: r.statusCode < 300, command, timelineId, statusCode: r.statusCode, body: r.body };
        }
        case 'stop': {
            timelineId = resolveTimelineId(input.contentId);
            const r = await httpRequest('POST', '/v0/timelines/' + timelineId + '/stop');
            return { success: r.statusCode < 300, command, timelineId, statusCode: r.statusCode, body: r.body };
        }
        case 'pause': {
            timelineId = resolveTimelineId(input.contentId);
            const r = await httpRequest('POST', '/v0/timelines/' + timelineId + '/pause');
            return { success: r.statusCode < 300, command, timelineId, statusCode: r.statusCode, body: r.body };
        }
        case 'setVar': {
            const r = await httpRequest('PUT', '/v0/vars/' + encodeURIComponent(input.varName), { value: input.varValue });
            return { success: r.statusCode < 300, command, statusCode: r.statusCode, body: r.body };
        }
        case 'getState': {
            const r = await httpRequest('GET', '/v0/state');
            return { success: r.statusCode < 300, command, statusCode: r.statusCode, body: r.body };
        }
        default:
            throw new Error('Unknown command: \'' + command + '\'');
    }
}

execute().then(payload => {
    node.send({ payload, topic: 'watchout/' + command });
}).catch(err => {
    node.send({ payload: { success: false, command, error: err.message }, topic: 'watchout/' + command });
});

return null;

// ─── Watchout SSE Monitor ──────────────────────────────────────────
// Connects to /v0/events SSE stream. Sends state events on output 1.
// Sends status (connected/disconnected/error) on output 2.
// Automatically reconnects on failure (5 s delay).
// Falls back to polling via the separate poll inject node.

'use strict';

const http = require('http');

const cfg  = flow.get('watchout_config') || {};
const host = cfg.host || 'localhost';
const port = cfg.port || 3019;
const SSE_RECONNECT_DELAY_MS = 5000;

// Prevent duplicate connections
if (context.get('sseConnected') === true) {
    return null;
}

function connect() {
    if (context.get('sseConnected') === true) return;

    const req = http.request(
        { hostname: host, port, path: '/v0/events', method: 'GET',
          headers: { 'Accept': 'text/event-stream', 'Cache-Control': 'no-cache' } },
        (res) => {
            if (res.statusCode !== 200) {
                res.destroy();
                context.set('sseConnected', false);
                flow.set('watchout_sse_status', 'error');
                node.send([null, { payload: { status: 'sse_error', message: 'SSE endpoint returned HTTP ' + res.statusCode } }]);
                setTimeout(connect, SSE_RECONNECT_DELAY_MS);
                return;
            }

            context.set('sseConnected', true);
            flow.set('watchout_sse_status', 'connected');
            node.send([null, { payload: { status: 'sse_connected' } }]);

            let buffer = '';

            res.on('data', (chunk) => {
                buffer += chunk.toString();
                const parts = buffer.split('\n\n');
                buffer = parts.pop();
                for (const block of parts) {
                    const event = {};
                    for (const line of block.split('\n')) {
                        if (line.startsWith('event:')) {
                            event.type = line.slice(6).trim();
                        } else if (line.startsWith('data:')) {
                            const raw = line.slice(5).trim();
                            try { event.data = JSON.parse(raw); }
                            catch(e) { event.data = raw; }
                        }
                    }
                    if (event.type || event.data !== undefined) {
                        flow.set('watchout_state', event.data || event);
                        node.send([{ payload: event, topic: 'watchout/state' }, null]);
                    }
                }
            });

            res.on('end', () => {
                context.set('sseConnected', false);
                context.set('sseRequest', null);
                flow.set('watchout_sse_status', 'disconnected');
                node.send([null, { payload: { status: 'sse_disconnected' } }]);
                setTimeout(connect, SSE_RECONNECT_DELAY_MS);
            });

            res.on('error', (err) => {
                context.set('sseConnected', false);
                context.set('sseRequest', null);
                flow.set('watchout_sse_status', 'error');
                node.send([null, { payload: { status: 'sse_error', message: err.message } }]);
                setTimeout(connect, SSE_RECONNECT_DELAY_MS);
            });
        }
    );

    req.on('error', (err) => {
        context.set('sseConnected', false);
        context.set('sseRequest', null);
        flow.set('watchout_sse_status', 'error');
        node.send([null, { payload: { status: 'sse_error', message: err.message } }]);
        setTimeout(connect, SSE_RECONNECT_DELAY_MS);
    });

    req.end();
    context.set('sseRequest', req);
}

// Cleanup on redeploy
node.on('close', function() {
    const r = context.get('sseRequest');
    if (r) { try { r.destroy(); } catch(e) {} }
    context.set('sseConnected', false);
    context.set('sseRequest', null);
    flow.set('watchout_sse_status', 'disconnected');
});

connect();
return null;

// ─── Watchout Poll Fallback ────────────────────────────────────────
// Runs every 5 s. Only polls if SSE is disconnected.

'use strict';

const http = require('http');

// Skip if SSE is working
if (flow.get('watchout_sse_status') === 'connected') {
    return null;
}

const cfg  = flow.get('watchout_config') || {};
const host = cfg.host || 'localhost';
const port = cfg.port || 3019;

const req = http.request(
    { hostname: host, port, path: '/v0/state', method: 'GET',
      headers: { 'Content-Type': 'application/json' } },
    (res) => {
        let data = '';
        res.on('data', c => { data += c; });
        res.on('end', () => {
            try {
                const state = JSON.parse(data);
                flow.set('watchout_state', state);
                node.send({ payload: { type: 'poll', data: state }, topic: 'watchout/state' });
            } catch(e) {
                node.warn('[Watchout Poll] Invalid JSON from /v0/state');
            }
        });
        res.on('error', err => { node.warn('[Watchout Poll] ' + err.message); });
    }
);
req.on('error', err => { node.warn('[Watchout Poll] ' + err.message); });
req.setTimeout(10000, () => req.destroy(new Error('timeout')));
req.end();
return null;
